Scripts.OnEnter:
GameTooltip:SetOwner( this );
GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Up), 0, 1, 1 );
GameTooltip:Show();

GameTooltip:SetOwner( this );
GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Down), 0, 1, 1 );
GameTooltip:Show();

GameTooltip:SetOwner( this );
if this:IsChecked() then
	GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Enable), 0, 1, 1 );
else
	GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Disable), 0.4, 0.4, 0.4 );
end
GameTooltip:Show();

Scripts.OnClick:
if this:IsChecked() then
	GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Enable), 0, 1, 1 );
else
	GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Disable), 0.4, 0.4, 0.4 );
end
COMBAT_ENGINE_CUSTOM_PRESETS[COMBAT_ENG_SERIAL][this:GetParent():GetID()].enabled = this:IsChecked();

Scripts.OnEnter:
local text = _G.CE_LANG.Main.Share;
GameTooltip:SetOwner( this );
GameTooltip:SetText( text, 0, 1, 1 );
GameTooltip:Show();

GameTooltip:SetOwner( this );
GameTooltip:SetText("|cff00FFFF/run CombatEngine(" .. this:GetID() .. ")|r");
GameTooltip:AddSeparator();
GameTooltip:AddLine("|cffFFFF00Right Click to copy macro|r");
GameTooltip:Show();

if this._Name:IsDrawDot() then
	GTT_SetSimpleVisual(GameTooltip);
	GameTooltip:SetOwner(this, "ANCHOR_TOPRIGHT");
	GameTooltip:SetText(this._Name:GetText(), 0, 1, 1);
	GameTooltip:Show();
end

Scripts.OnClick:
local range = {
	[1] = 0,
	[2] = 730,
	[3] = 1520,
	[4] = 1900,
}
CombatEngine_ScrollFrame:SetHorizontalScroll( range[this:GetID()] );
COMBAT_ENGINE_SELECTED_CATEGORY = this:GetID();
for i = 1, 4 do
	local button = _G["COMBATENGINE_EDIT_LUA_CONDITIONS_Section_" .. i];
	if i == this:GetID() then
		button:LockHighlight();
	else
		button:UnlockHighlight();
	end
end

Scripts.OnShow:
if COMBAT_ENGINE_SELECTED_CATEGORY == this:GetID() then
	this:LockHighlight();
else
	this:UnlockHighlight();
end

Scripts.OnEnter:
GameTooltip:SetOwner(this,"ANCHOR_CENTER",0,0);
GameTooltip:ClearAllAnchors();
GameTooltip:SetAnchor("CENTER","CENTER",this,0,0);
GameTooltip:SetText( TEXT("C_CLOSE") );
GameTooltip:Show();

Scripts.OnLoad:
this:SetValueStepMode("INT");
this:SetMaxValue( COMBAT_ENG_MAXSKILLS - COMBAT_ENG_MAX_DISPLAY_SKILLS );
this:SetMinValue( 0 );
this:SetValue( 0 );

Scripts.OnEnter:
GameTooltip:SetOwner( this );
GameTooltip:SetText( TEXT(CE_LANG.Tooltip.Import), 1, 0, 0 );
GameTooltip:Show();

Scripts.OnShow:
COMBATENGINE_EDIT_LUA_OnShow( this );
CombatEngine_CONFIG_OnShow( this );
local main, sec =  UnitClassToken("player");
if main ~= "THIEF" and main ~= "HARPSYN" and main ~= "MAGE" then
	this.Import:Hide();
else
	this.Import:Show();
end

Scripts.OnKeyDown:
if IsCtrlKeyDown() and not IsShiftKeyDown() and not IsAltKeyDown() and key == "A" then
	this:HighlightText();
end

if IsCtrlKeyDown() and not IsShiftKeyDown() and not IsAltKeyDown() and key == "A" then
	this:HighlightText();
end

if IsCtrlKeyDown() and not IsShiftKeyDown() and not IsAltKeyDown() and key == "A" then
	this:HighlightText();
end

