Scripts.OnLoad:
this:SetAlpha( 0.65 );
if GetLanguage() == "PL" then
	this:GetNormalTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button_PL.tga" );
	this:GetPushedTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button_PL.tga" );
	this:GetHighlightTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button_PL.tga" );
elseif GetLanguage() == "ES" then
	this:GetNormalTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button_ES.tga" );
	this:GetPushedTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button_ES.tga" );
	this:GetHighlightTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button_ES.tga" );
else
	this:GetNormalTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button.tga" );
	this:GetPushedTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button.tga" );
	this:GetHighlightTexture():SetTexture( "Interface\\addons\\CombatEngine\\texture\\Custom\\Save_Button.tga" );
end
